import{_ as r,o as a,c as o,a2 as s}from"./chunks/framework.BWuWLRhz.js";const e="/assets/v2rayN-for-windows-0.CbewJ9y7.png",n="/assets/v2rayN-for-windows-1.OIP43UnL.png",d="/assets/v2rayN-for-windows-2.BK-g9VMT.png",i="/assets/v2rayN-for-windows-3.ByDsR4VL.png",l="/assets/v2rayN-for-windows-4.ZUbX9rf2.png",h="/assets/v2rayN-for-windows-5.BMFgD_Zd.png",p="/assets/v2rayN-for-windows-6.BKWoUbRa.png",y=JSON.parse('{"title":"v2rayN for Windows","description":"Windows 备选客户端 v2rayN 图文配置教程，七步完成从启动到连接。","frontmatter":{"description":"Windows 备选客户端 v2rayN 图文配置教程，七步完成从启动到连接。"},"headers":[],"relativePath":"clients/windows/v2rayn.md","filePath":"clients/windows/v2rayn.md","lastUpdated":1783294793000}'),g={name:"clients/windows/v2rayn.md"};function c(b,t,f,u,w,m){return a(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="v2rayn-for-windows" tabindex="-1">v2rayN for Windows <a class="header-anchor" href="#v2rayn-for-windows" aria-label="Permalink to &quot;v2rayN for Windows&quot;">​</a></h1><blockquote><p><strong>Windows 轻量客户端</strong> | 高兼容、支持主流协议。Windows 首选推荐见 <a href="./clash-verge">Clash Verge Rev</a>。</p></blockquote><p><a href="https://github.com/2dust/v2rayN" target="_blank" rel="noreferrer">v2rayN</a> 是 Windows 上非常成熟的代理客户端，支持 VMess、VLESS、Trojan、Shadowsocks 等协议，适合需要稳定订阅使用和快速排障的用户。</p><h2 id="协议支持" tabindex="-1">协议支持 <a class="header-anchor" href="#协议支持" aria-label="Permalink to &quot;协议支持&quot;">​</a></h2><table tabindex="0"><thead><tr><th>协议类型</th><th>支持状态</th></tr></thead><tbody><tr><td><strong>Shadowsocks (SS)</strong></td><td>完全支持</td></tr><tr><td><strong>Trojan</strong></td><td>完全支持</td></tr><tr><td><strong>VMess</strong></td><td>完全支持</td></tr><tr><td><strong>VLESS</strong></td><td>完全支持</td></tr><tr><td><strong>SOCKS5</strong></td><td>完全支持</td></tr></tbody></table><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>最低要求</th><th>推荐配置</th></tr></thead><tbody><tr><td><strong>操作系统</strong></td><td>Windows 10/11</td><td>Windows 11</td></tr><tr><td><strong>处理器</strong></td><td>双核 CPU</td><td>四核及以上</td></tr><tr><td><strong>内存</strong></td><td>4GB</td><td>8GB 及以上</td></tr><tr><td><strong>存储空间</strong></td><td>200MB</td><td>1GB 及以上</td></tr></tbody></table><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><ul><li>Windows x64（直链）：<a href="https://github.com/2dust/v2rayN/releases/download/7.19.5/v2rayN-windows-64.zip" target="_blank" rel="noreferrer">下载 zip</a></li><li>Windows ARM64（直链）：<a href="https://github.com/2dust/v2rayN/releases/download/7.19.5/v2rayN-windows-arm64.zip" target="_blank" rel="noreferrer">下载 zip</a></li><li>镜像加速：在上述直链前加前缀 <code>https://gh.xxooo.cf/</code></li><li>当前参考版本：<code>7.19.5</code></li></ul><p>安装说明：下载 zip 后解压到独立目录（建议 <code>D:\\Apps\\v2rayN</code>），无需安装。</p><h2 id="配置教程" tabindex="-1">配置教程 <a class="header-anchor" href="#配置教程" aria-label="Permalink to &quot;配置教程&quot;">​</a></h2><h3 id="步骤一-启动客户端" tabindex="-1">步骤一：启动客户端 <a class="header-anchor" href="#步骤一-启动客户端" aria-label="Permalink to &quot;步骤一：启动客户端&quot;">​</a></h3><p>解压后双击 <strong>v2rayN.exe</strong> 启动程序。首次运行如提示组件安装，按提示完成即可。</p><p><img src="'+e+'" alt="双击 v2rayN.exe 启动"></p><h3 id="步骤二-复制订阅链接" tabindex="-1">步骤二：复制订阅链接 <a class="header-anchor" href="#步骤二-复制订阅链接" aria-label="Permalink to &quot;步骤二：复制订阅链接&quot;">​</a></h3><p>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">自由港机场会员中心</a>，在「我的订阅」的订阅链接区域，点击右侧的<strong>复制</strong>按钮复制订阅链接。</p><p><img src="'+n+'" alt="在会员中心复制订阅链接"></p><h3 id="步骤三-导入订阅" tabindex="-1">步骤三：导入订阅 <a class="header-anchor" href="#步骤三-导入订阅" aria-label="Permalink to &quot;步骤三：导入订阅&quot;">​</a></h3><p>回到 v2rayN，点击顶部菜单的<strong>服务器</strong>，选择<strong>从剪贴板导入分享链接（Ctrl+V）</strong>，即可导入刚才复制的订阅。</p><p><img src="'+d+'" alt="服务器菜单选择从剪贴板导入"></p><h3 id="步骤四-更新订阅" tabindex="-1">步骤四：更新订阅 <a class="header-anchor" href="#步骤四-更新订阅" aria-label="Permalink to &quot;步骤四：更新订阅&quot;">​</a></h3><p>点击顶部菜单的<strong>订阅分组</strong>，选择<strong>更新全部订阅（不通过代理）</strong>，拉取最新节点。</p><p><img src="'+i+'" alt="订阅分组更新全部订阅"></p><h3 id="步骤五-开启系统代理" tabindex="-1">步骤五：开启系统代理 <a class="header-anchor" href="#步骤五-开启系统代理" aria-label="Permalink to &quot;步骤五：开启系统代理&quot;">​</a></h3><p>在底部的<strong>系统代理</strong>下拉框中，选择<strong>自动配置系统代理</strong>即可开启代理。（选择「清除系统代理」即可关闭代理。）</p><p><img src="'+l+'" alt="系统代理选择自动配置系统代理"></p><h3 id="步骤六-选择节点" tabindex="-1">步骤六：选择节点 <a class="header-anchor" href="#步骤六-选择节点" aria-label="Permalink to &quot;步骤六：选择节点&quot;">​</a></h3><p>在节点列表中<strong>右键点击</strong>目标节点，选择<strong>设为活动服务器（Enter）</strong>，即可切换到该节点。建议选择延迟较低的节点。</p><p><img src="'+h+'" alt="右键节点设为活动服务器"></p><p>完成后打开浏览器访问外网，验证是否连接正常。</p><h3 id="步骤七-结束使用" tabindex="-1">步骤七：结束使用 <a class="header-anchor" href="#步骤七-结束使用" aria-label="Permalink to &quot;步骤七：结束使用&quot;">​</a></h3><p>使用完毕后，在电脑右下角<strong>右键点击</strong> v2rayN 托盘图标，选择<strong>退出</strong>即可关闭软件并恢复直连。</p><p><img src="'+p+'" alt="托盘右键退出 v2rayN"></p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><ul><li><strong>订阅管理</strong>：多订阅并存，支持手动刷新快速同步新节点</li><li><strong>代理模式</strong>：系统代理（全局）、PAC 分流（规则）、手动代理（本地端口）</li><li><strong>状态监控</strong>：节点延迟测试、实时流量统计、连接与错误日志</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 订阅更新失败？</strong> A: 先在浏览器打开订阅链接确认可访问，再检查本地网络、系统时间，最后重新导入订阅。</p><p><strong>Q: 已连接但无法上网？</strong> A: 检查系统代理是否为「自动配置系统代理」；切换节点测试；确认安全软件未拦截 v2rayN。</p><p><strong>Q: 节点速度慢？</strong> A: 优先同地区低延迟节点；避免高峰期拥堵节点；定期更新订阅。</p><p>更多问题见<a href="./../../guide/faq">常见问题 FAQ</a>。</p><hr><blockquote><p>最后更新：2026 年 3 月 28 日 · 适用版本 v2rayN 7.19.5</p></blockquote>',42)])])}const v=r(g,[["render",c]]);export{y as __pageData,v as default};
